                  <span className="text-[9px] font-black uppercase bg-white/20 px-1.5 py-0.5 rounded">
                    {t.time || '1m'}
                  </span>
                )}
              </div>
              <p className="text-[11px] font-bold mt-2">
                {isFree ? 'Available' : `${t.status} — ₹${t.currentBill || 0}`}
              </p>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export function BarMenuPage() {
  const { menuItems, loading, error, refreshMenu } = useBarMenuSync();
  const [barMenuTab, setBarMenuTab] = useState('food');
  const [filter, setFilter] = useState('');

  // Edit modal state
  const [editItem, setEditItem] = useState(null);
  const [editName, setEditName] = useState('');
  const [editType, setEditType] = useState('veg');
  const [editPrice, setEditPrice] = useState('');
  const [editImg, setEditImg] = useState(null);
  const [editSaving, setEditSaving] = useState(false);

  // Add modal state
  const [showAdd, setShowAdd] = useState(false);
  const [addName, setAddName] = useState('');
  const [addCategory, setAddCategory] = useState('');
  const [addType, setAddType] = useState('veg');
  const [addPrice, setAddPrice] = useState('');
  const [addMenuType, setAddMenuType] = useState('FOOD');
  const [addImg, setAddImg] = useState(null);        // raw File object
  const [addImgPreview, setAddImgPreview] = useState(''); // object URL for preview
  const [addUploading, setAddUploading] = useState(false); // true while Cloudinary upload in-flight
  const [addSaving, setAddSaving] = useState(false);

  // Delete state
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [deleteWorking, setDeleteWorking] = useState(false);

  // Toast
  const [toast, setToast] = useState(null);
  const showToast = (msg, type = 'success') => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 2800);
  };

  const filteredItems = useMemo(() => {
    const typeFilter = barMenuTab === 'food' ? 'FOOD' : 'LIQUOR';
    return menuItems.filter(
      (item) =>
        item.menuType === typeFilter &&
        (!filter || item.n.toLowerCase().includes(filter.toLowerCase()))
    );
  }, [menuItems, barMenuTab, filter]);

  // Image resize helper (canvas → base64)
  const compressImage = (file, cb) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new window.Image();
      img.onload = () => {
        const MAX = 400;
        const ratio = Math.min(MAX / img.width, MAX / img.height, 1);
        const canvas = document.createElement('canvas');
        canvas.width = img.width * ratio;
        canvas.height = img.height * ratio;
        canvas.getContext('2d').drawImage(img, 0, 0, canvas.width, canvas.height);
        cb(canvas.toDataURL('image/jpeg', 0.7));
      };
      img.src = e.target.result;
    };
    reader.readAsDataURL(file);
  };

  // Open edit modal
  const openEdit = (item) => {
    setEditItem(item);
    setEditName(item.n);
    setEditType(item.t || 'veg');
    setEditPrice(item.variants.length === 1 ? String(item.variants[0].price) : '');
    setEditImg(item.img || null);
  };

  // Cloudinary direct upload — bypasses backend proxy for 2-4s vs 10-15s latency
  const uploadImageToCloudinary = async (base64DataUri) => {
    // Convert base64 data URI → Blob for multipart/form-data upload
    const [, b64] = base64DataUri.split(',');
    const bytes = Uint8Array.from(atob(b64), (c) => c.charCodeAt(0));
    const blob = new Blob([bytes], { type: 'image/jpeg' });

    const formData = new FormData();
    formData.append('file', blob, 'image.jpg');
    formData.append('upload_preset', import.meta.env.VITE_CLOUDINARY_UPLOAD_PRESET || 'softshape-vgrand-menu');

    const cloudName = import.meta.env.VITE_CLOUDINARY_CLOUD_NAME || 'dnlhxmtqu';
    const res = await fetch(
      `https://api.cloudinary.com/v1_1/${cloudName}/image/upload`,
      { method: 'POST', body: formData }
    );
    const data = await res.json();
    if (!data.secure_url) throw new Error(data?.error?.message || 'Cloudinary upload failed');
    return data.secure_url;
  };

  const saveEdit = async () => {
    if (!editName.trim()) return;
    setEditSaving(true);

    let imageUrl = undefined;
    if (editImg && editImg.startsWith('data:')) {
      // New local file picked — upload to Cloudinary first
      try {
        imageUrl = await uploadImageToCloudinary(editImg);
      } catch {
        showToast('Image upload failed', 'error');
        setEditSaving(false);
        return;
      }
    }
    // If editImg is an existing https URL — skip (don't re-upload)
    // If editImg is null — skip (don't touch imageUrl)

    const patch = { n: editName.trim(), t: editType };
    if (editPrice !== '') patch.p = Number(editPrice);
    if (imageUrl !== undefined) patch.img = imageUrl;   // updateBarMenuItem maps patch.img → body.imageUrl

    updateBarMenuItem(editItem.id, patch, API_BASE);
    setEditSaving(false);
    setEditItem(null);
    showToast('Item updated');
  };


  // Availability toggle
  const toggleAvailability = (item) => {
    toggleBarMenuAvailability(
      item.id,
      API_BASE,
      () => showToast(item.isAvailable === false ? 'Item enabled' : 'Item disabled'),
      () => showToast('Toggle failed', 'error')
    );
  };

  // Delete
  const confirmDelete = async () => {
    if (!deleteTarget || deleteWorking) return; // guard double-tap
    setDeleteWorking(true);
    try {
      const res = await fetch(`${API_BASE}/api/bar/menu/items/${deleteTarget.id}`, { method: 'DELETE' });
      if (res.ok) { showToast('Item deleted'); refreshMenu(); }
      else showToast('Delete failed', 'error');
    } catch { showToast('Delete failed', 'error'); }
    setDeleteWorking(false);
    setDeleteTarget(null);
  };

  // Add item
  const resetAddModal = () => {
    setShowAdd(false);
    setAddName('');
    setAddCategory('');
    setAddPrice('');
    setAddImg(null);
    setAddImgPreview('');
  };

  const saveAdd = async () => {
    if (!addName.trim() || !addPrice) return;
    setAddSaving(true);
    try {
      // Step 1: if a file was picked, compress then upload to Cloudinary via backend proxy
      let imageUrl = '';
      if (addImg) {
        setAddUploading(true);
        try {
          // Compress to base64 first (reuse existing helper)
          const base64 = await new Promise((resolve, reject) => {
            compressImage(addImg, (b64) => resolve(b64));
          });
          // Upload via backend proxy (same as Edit modal)
          imageUrl = await uploadImageToCloudinary(base64);
        } catch {
          showToast('Image upload failed', 'error');
          setAddUploading(false);
          setAddSaving(false);
          return;
        }
        setAddUploading(false);
      }

      // Step 2: POST with the CDN imageUrl (or empty string if no image)
      const body = {
        name: addName.trim(),
        category: addCategory.trim() || 'General',
        isVeg: addType === 'veg',
        price: Number(addPrice),
        menuType: addMenuType,
        ...(imageUrl ? { imageUrl } : {}),
      };
      const res = await fetch(`${API_BASE}/api/bar/menu/items`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      if (res.ok) { showToast('Item added'); refreshMenu(); resetAddModal(); }
      else showToast('Add failed', 'error');
    } catch { showToast('Add failed', 'error'); }
    setAddSaving(false);
  };

  if (loading) return (
    <div className="flex items-center justify-center py-20">
      <div className="w-6 h-6 border-2 border-[#E53935] border-t-transparent rounded-full animate-spin" />
    </div>
  );

  return (
    <div className="space-y-4 font-sans">
      {/* Toast */}
      {toast && (
        <div className={`fixed top-4 right-4 z-[9999] px-4 py-2 rounded-xl text-white text-[12px] font-bold shadow-lg transition-all ${toast.type === 'error' ? 'bg-red-500' : 'bg-green-500'}`}>
          {toast.msg}
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
        <h3 className="font-semibold">Bar Menu</h3>
        <div className="flex items-center gap-2 flex-wrap">
          <BarMenuToggle active={barMenuTab} onChange={setBarMenuTab} />
          <input
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            placeholder="Search..."
            className="border border-gray-200 rounded-xl px-3 py-1.5 text-[12px] font-bold w-40 focus:outline-none focus:border-[#E53935]"
          />
          <button
            onClick={() => setShowAdd(true)}
            className="px-3 py-1.5 bg-[#E53935] text-white text-[12px] font-bold rounded-xl hover:bg-red-700 transition"
          >
            + Add Item
          </button>
        </div>
      </div>

      {error && (
        <div className="p-3 bg-red-50 border border-red-200 rounded-xl text-[12px] text-red-600 font-bold">
          {error} — <button onClick={refreshMenu} className="underline">Retry</button>
        </div>
      )}

      {/* Item list */}
      <div className="space-y-1">
        {filteredItems.map((item) => (
          <div
            key={item.id}
            className={`flex items-center justify-between p-3 bg-white rounded-xl border transition ${item.isAvailable === false ? 'border-gray-200 opacity-60' : 'border-gray-100'}`}
          >
            {/* Left */}
            <div className="flex items-center gap-3">
              {item.img ? (
                <img src={item.img} alt={item.n} className="w-9 h-9 rounded-lg object-cover flex-shrink-0" />
              ) : item.menuType === 'FOOD' ? (
                <span className={`w-4 h-4 rounded-full border-2 flex-shrink-0 ${item.t === 'veg' ? 'border-green-600 bg-green-100' : 'border-red-600 bg-red-100'}`} />
              ) : (
                <span className="text-[14px]">🥃</span>
              )}
              <div>
                <p className="text-[13px] font-bold text-gray-900">{item.n}</p>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">{item.c}</p>
              </div>
            </div>

            {/* Right */}
            <div className="flex items-center gap-2">
              {item.variants.length === 1 ? (
                <p className="text-[13px] font-black text-gray-900">₹{item.variants[0].price}</p>
              ) : (
                <div className="flex flex-wrap gap-1 justify-end max-w-[140px]">
                  {item.variants.map((v) => (
                    <span key={v.id} className="text-[10px] font-bold bg-gray-100 px-2 py-0.5 rounded-full text-gray-700">
                      {v.name}: ₹{v.price}
                    </span>
                  ))}
                </div>
              )}

              {/* Availability toggle */}
              <button
                onClick={() => toggleAvailability(item)}
                title={item.isAvailable === false ? 'Mark available' : 'Mark unavailable'}
                className={`text-[11px] px-2 py-0.5 rounded-full font-bold border transition ${item.isAvailable === false ? 'border-gray-300 text-gray-400 bg-gray-50' : 'border-green-300 text-green-700 bg-green-50'}`}
              >
                {item.isAvailable === false ? 'Off' : 'On'}
              </button>

              {/* Edit */}
              <button
                onClick={() => openEdit(item)}
                className="p-1.5 rounded-lg hover:bg-gray-100 text-gray-500 hover:text-gray-800 transition"
                title="Edit"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536M9 13l6.586-6.586a2 2 0 112.828 2.828L11.828 15.828a2 2 0 01-1.414.586H9v-2a2 2 0 01.586-1.414z" />
                </svg>
              </button>

              {/* Delete */}
              <button
                onClick={() => setDeleteTarget(item)}
                className="p-1.5 rounded-lg hover:bg-red-50 text-gray-400 hover:text-red-600 transition"
                title="Delete"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6M9 7h6m2 0a1 1 0 00-1-1h-4a1 1 0 00-1 1m-4 0h10" />
                </svg>
              </button>
            </div>
          </div>
        ))}

        {filteredItems.length === 0 && (
          <p className="text-center text-[12px] text-gray-400 font-bold py-8">No items found</p>
        )}
      </div>

      {/* ── EDIT MODAL ── */}
      {editItem && (
        <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-5 w-full max-w-sm space-y-4 shadow-2xl">
            <h4 className="font-bold text-[14px]">Edit Item</h4>

            {/* Image */}
            <div className="flex items-center gap-3">
              {editImg ? (
                <img src={editImg} alt="" className="w-14 h-14 rounded-xl object-cover border" />
              ) : (
                <div className="w-14 h-14 rounded-xl bg-gray-100 flex items-center justify-center text-2xl">{editItem.menuType === 'FOOD' ? '🍽️' : '🥃'}</div>
              )}
              <label className="cursor-pointer px-3 py-1.5 border border-gray-300 rounded-xl text-[11px] font-bold text-gray-600 hover:border-[#E53935] transition">
                Change Photo
                <input type="file" accept="image/*" className="hidden" onChange={(e) => {
                  if (e.target.files[0]) compressImage(e.target.files[0], setEditImg);
                }} />
              </label>
            </div>

            {/* Name */}
            <div>
              <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider">Name</label>
              <input
                value={editName}
                onChange={(e) => setEditName(e.target.value)}
                className="mt-1 w-full border border-gray-200 rounded-xl px-3 py-2 text-[13px] font-bold focus:outline-none focus:border-[#E53935]"
              />
            </div>

            {/* Type (food items only) */}
            {editItem.menuType === 'FOOD' && (
              <div>
                <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider">Type</label>
                <div className="flex gap-2 mt-1">
                  {['veg', 'non'].map((t) => (
                    <button
                      key={t}
                      onClick={() => setEditType(t)}
                      className={`flex-1 py-1.5 rounded-xl text-[12px] font-bold border transition ${editType === t ? (t === 'veg' ? 'border-green-500 bg-green-50 text-green-700' : 'border-red-500 bg-red-50 text-red-700') : 'border-gray-200 text-gray-500'}`}
                    >
                      {t === 'veg' ? '🟢 Veg' : '🔴 Non-Veg'}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Price (single-variant only) */}
            {editItem.variants.length === 1 && (
              <div>
                <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider">Price (₹)</label>
                <input
                  type="number"
                  value={editPrice}
                  onChange={(e) => setEditPrice(e.target.value)}
                  className="mt-1 w-full border border-gray-200 rounded-xl px-3 py-2 text-[13px] font-bold focus:outline-none focus:border-[#E53935]"
                />
              </div>
            )}

            {editItem.variants.length > 1 && (
              <p className="text-[11px] text-gray-400 font-bold">Multi-variant pricing — edit from backend</p>
            )}

            <div className="flex gap-2 pt-1">
              <button onClick={() => setEditItem(null)} className="flex-1 py-2 border border-gray-200 rounded-xl text-[12px] font-bold text-gray-600 hover:bg-gray-50 transition">Cancel</button>
              <button
                onClick={saveEdit}
                disabled={editSaving || !editName.trim()}
                className="flex-1 py-2 bg-[#E53935] text-white rounded-xl text-[12px] font-bold hover:bg-red-700 disabled:opacity-50 transition"
              >
                {editSaving ? 'Saving...' : 'Save'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── ADD MODAL ── */}
      {showAdd && (
        <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-5 w-full max-w-sm space-y-4 shadow-2xl max-h-[90vh] overflow-y-auto">
            <h4 className="font-bold text-[14px]">Add Bar Item</h4>

            {/* Image */}
            <div className="flex items-center gap-3">
              {addImgPreview ? (
                <img src={addImgPreview} alt="" className="w-14 h-14 rounded-xl object-cover border" />
              ) : (
                <div className="w-14 h-14 rounded-xl bg-gray-100 flex items-center justify-center text-gray-400 text-xs font-bold">Photo</div>
              )}
              <label className="cursor-pointer px-3 py-1.5 border border-gray-300 rounded-xl text-[11px] font-bold text-gray-600 hover:border-[#E53935] transition">
                Upload Photo
                <input type="file" accept="image/*" className="hidden" onChange={(e) => {
                  const file = e.target.files[0];
                  if (file) {
                    setAddImg(file);                               // store raw File for upload
                    setAddImgPreview(URL.createObjectURL(file));   // object URL for instant preview
                  }
                }} />
              </label>
            </div>

            {/* Menu type toggle */}
            <div>
              <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider">Menu Section</label>
              <div className="flex gap-2 mt-1">
                {['FOOD', 'LIQUOR'].map((mt) => (
                  <button key={mt} onClick={() => setAddMenuType(mt)}
                    className={`flex-1 py-1.5 rounded-xl text-[12px] font-bold border transition ${addMenuType === mt ? 'border-[#E53935] bg-red-50 text-[#E53935]' : 'border-gray-200 text-gray-500'}`}>
                    {mt === 'FOOD' ? '🍽️ Food' : '🥃 Liquor'}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider">Name *</label>
              <input value={addName} onChange={(e) => setAddName(e.target.value)}
                className="mt-1 w-full border border-gray-200 rounded-xl px-3 py-2 text-[13px] font-bold focus:outline-none focus:border-[#E53935]"
                placeholder="e.g. Chicken Tikka" />
            </div>

            <div>
              <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider">Category</label>
              <input value={addCategory} onChange={(e) => setAddCategory(e.target.value)}
                className="mt-1 w-full border border-gray-200 rounded-xl px-3 py-2 text-[13px] font-bold focus:outline-none focus:border-[#E53935]"
                placeholder="e.g. Starters" />
            </div>

            {addMenuType === 'FOOD' && (
              <div>
                <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider">Type</label>
                <div className="flex gap-2 mt-1">
                  {['veg', 'non'].map((t) => (
                    <button key={t} onClick={() => setAddType(t)}
                      className={`flex-1 py-1.5 rounded-xl text-[12px] font-bold border transition ${addType === t ? (t === 'veg' ? 'border-green-500 bg-green-50 text-green-700' : 'border-red-500 bg-red-50 text-red-700') : 'border-gray-200 text-gray-500'}`}>
                      {t === 'veg' ? '🟢 Veg' : '🔴 Non-Veg'}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div>
              <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider">Price (₹) *</label>
              <input type="number" value={addPrice} onChange={(e) => setAddPrice(e.target.value)}
                className="mt-1 w-full border border-gray-200 rounded-xl px-3 py-2 text-[13px] font-bold focus:outline-none focus:border-[#E53935]"
                placeholder="0" />
            </div>

            <div className="flex gap-2 pt-1">
              <button onClick={resetAddModal} disabled={addSaving || addUploading} className="flex-1 py-2 border border-gray-200 rounded-xl text-[12px] font-bold text-gray-600 hover:bg-gray-50 disabled:opacity-50 transition">Cancel</button>
              <button onClick={saveAdd} disabled={addSaving || addUploading || !addName.trim() || !addPrice}
                className="flex-1 py-2 bg-[#E53935] text-white rounded-xl text-[12px] font-bold hover:bg-red-700 disabled:opacity-50 transition">
                {addUploading ? 'Uploading image...' : addSaving ? 'Adding...' : 'Add Item'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── DELETE CONFIRM ── */}
      {deleteTarget && (
        <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-5 w-full max-w-xs space-y-4 shadow-2xl text-center">
            <div className="text-3xl">🗑️</div>
            <p className="font-bold text-[14px]">Remove "{deleteTarget.n}"?</p>
            <p className="text-[12px] text-gray-500">This item will be hidden from all menus.</p>
            <div className="flex gap-2">
              <button onClick={() => setDeleteTarget(null)} className="flex-1 py-2 border border-gray-200 rounded-xl text-[12px] font-bold text-gray-600 hover:bg-gray-50 transition">Cancel</button>
              <button onClick={confirmDelete} disabled={deleteWorking}
                className="flex-1 py-2 bg-red-600 text-white rounded-xl text-[12px] font-bold hover:bg-red-700 disabled:opacity-50 transition">
                {deleteWorking ? 'Deleting...' : 'Delete'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useEffect, useState, useRef, Suspense, lazy } from 'react';
import { 
  LayoutDashboard, 
  Table2, 
  UtensilsCrossed, 
  ClipboardList, 
  ChartNoAxesCombined, 
  DollarSign, 
  Megaphone, 
  Camera, 
  Package, 
  Sparkles, 
  Settings, 
  LogOut, 
  Bell, 
  Search, 
  Bot,
  Send,
  Star
} from 'lucide-react';
import { 
  Dashboard, Tables, MenuPage, Orders, Reports, Payroll, Marketing, Pricing, SettingsPage, Inventory, BarTables, BarMenuPage
} from './AdminComponents';
import { useOutlet } from '../context/OutletContext';
import OutletToggle from '../shared/components/OutletToggle';
import SurveillanceDashboard from './SurveillanceDashboard';
import AIDishCreationModal from './AIDishCreationModal';
import TodaySpecials from './TodaySpecials';
import { useSocket } from '../hooks/useSocket';
import { RESTAURANT_ID } from '../services/tableApi';
import { BAR_ID } from '../services/barApiConfig';
import { useTableSync } from '../services/tableSyncService';
import { fetchTransactions } from '../services/orderApi';

const CaptainPerformanceDashboard = lazy(() => import("../captain/CaptainPerformanceDashboard"));

const navItems = [
  ["dashboard", "Dashboard", LayoutDashboard],
  ["tables", "Tables", Table2],
  ["menu", "Menu", UtensilsCrossed],
  ["specials", "Today Specials", Star],
  ["orders", "Orders", ClipboardList],
  ["reports", "Reports", ChartNoAxesCombined],
  ["captains", "Captain Analytics", ChartNoAxesCombined],
  ["payroll", "Payroll", DollarSign],
  ["marketing", "Marketing AI", Megaphone],
  ["surveillance", "Surveillance", Camera],
  ["inventory", "Inventory", Package],
  ["pricing", "Pricing", Sparkles],
  ["settings", "Settings", Settings],
];

const AdminDashboard = ({ role = 'admin', onLogout }) => {
  const [page, setPage] = useState(() => {
    const saved = localStorage.getItem('admin_active_tab');
    if (role === 'manager' && saved !== 'tables' && saved !== 'captains') return 'tables';
    if (saved === 'pos') return 'dashboard';
    return saved || (role === 'manager' ? 'tables' : 'dashboard');
  });
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [spireOpen, setSpireOpen] = useState(false);
  const [dishModalOpen, setDishModalOpen] = useState(false);
  
  // Marketing AI State
  const [mUpload, setMUpload] = useState(null);
  const [mGenerated, setMGenerated] = useState(false);
  const [mPosted, setMPosted] = useState(false);
  const mUploadRef = useRef(null);
  
  // Shared State
  const [revenue, setRevenue] = useState(0);
  const [ordersCount, setOrdersCount] = useState(0);
  const [statsLoading, setStatsLoading] = useState(true);
  const [activityLog, setActivityLog] = useState([
    { id: 1, text: "Raju closed Table 4 bill for ₹2,450", time: "2 min ago", type: "success" },
    { id: 2, text: "Lakshmi sent KOT for Table 12", time: "5 min ago", type: "info" },
  ]);
  const { setTables } = useTableSync();
  const { outlet } = useOutlet();
  const socket = useSocket(outlet === 'bar' ? BAR_ID : RESTAURANT_ID);

  useEffect(() => {
    const pushLog = (text, type = "info") => {
      setActivityLog((prev) => [
        { id: Date.now(), text, time: "Just now", type },
        ...prev,
      ].slice(0, 12));
    };

    const onOrderCreated = ({ order }) => pushLog(`New order for Table ${order?.table?.number || ''}`, "info");
    const onOrderUpdated = ({ order }) => pushLog(`Order ${order?.id?.slice(-6) || ''} updated`, "info");
    const onBillingRequested = ({ table }) => pushLog(`Billing requested for Table ${table?.number || ''}`, "warning");
    const onOrderPaid = ({ tableId }) => pushLog(`Payment completed for table ${tableId || ''}`, "success");
    
    const onTableUpdated = ({ table } = {}) => {
      if (!table) return;
      pushLog(`Table ${table.number} → ${table.workflowStatus || table.status}`, "info");
    };

    socket.on("order:created", onOrderCreated);
    socket.on("order:updated", onOrderUpdated);
    socket.on("billing:requested", onBillingRequested);
    socket.on("order:paid", onOrderPaid);
    socket.on("table:updated", onTableUpdated);

    return () => {
      socket.off("order:created", onOrderCreated);
      socket.off("order:updated", onOrderUpdated);
      socket.off("billing:requested", onBillingRequested);
      socket.off("order:paid", onOrderPaid);
      socket.off("table:updated", onTableUpdated);
    };
  }, [socket, setTables]);

  // ── Real stats fetch ─────────────────────────────────────────────────
  useEffect(() => {
    let cancelled = false;

    const loadStats = async () => {
      try {
        const [restaurantTxns, barTxns] = await Promise.allSettled([
          fetchTransactions(RESTAURANT_ID, 500),
          fetchTransactions(BAR_ID, 500),
        ]);
        const transactions = [
          ...(restaurantTxns.status === 'fulfilled' ? restaurantTxns.value : []),
          ...(barTxns.status === 'fulfilled' ? barTxns.value : []),
        ];
        if (cancelled) return;

        const todayStart = new Date();
        todayStart.setHours(0, 0, 0, 0);

        const todayTxns = transactions.filter(txn => {
          const txnDate = new Date(txn.paidAt || txn.createdAt);
          return txnDate >= todayStart;
        });

        setRevenue(Math.round(todayTxns.reduce((sum, txn) => sum + (txn.amount || 0), 0)));
        setOrdersCount(todayTxns.length);
      } catch (err) {
        console.warn('[AdminStats] Failed to load stats:', err.message);
        // Keep at 0 on failure — don’t show stale fake data
      } finally {
        if (!cancelled) setStatsLoading(false);
      }
    };

    loadStats();
    const interval = setInterval(loadStats, 60000);

    const onOrderPaidRefresh = () => loadStats();
    if (socket) socket.on('order:paid', onOrderPaidRefresh);

    return () => {
      cancelled = true;
      clearInterval(interval);
      if (socket) socket.off('order:paid', onOrderPaidRefresh);
    };
  }, [socket, outlet]);

  const displayNavItems = role === 'manager' 
    ? navItems.filter(item => item[0] === 'tables' || item[0] === 'captains')
    : navItems;

  const title = displayNavItems.find((x) => x[0] === page)?.[1] ?? "Dashboard";

  return (
    <div className="min-h-screen bg-[#FFF5F5] text-[#1A1A1A] font-sans">
      {/* Mobile Overlay */}
      {isSidebarOpen && (
        <div className="fixed inset-0 z-30 bg-black/50 md:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      <aside className={`fixed left-0 top-0 z-[60] flex h-[100dvh] w-[240px] flex-col bg-[#B71C1C] text-white transition-transform duration-300 md:translate-x-0 ${isSidebarOpen ? "translate-x-0" : "-translate-x-full"}`}>
        <div className="flex flex-col flex-grow overflow-hidden p-4">
          <div className="flex items-center justify-between flex-shrink-0 mb-2">
            <div className="bg-white p-4 rounded-[32px] shadow-2xl border border-white/10 aspect-square w-40 flex items-center justify-center">
              <img 
                src="/logo softshape.ai.png" 
                alt="Softshape.ai" 
                className="w-full h-full object-contain" 
              />
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden text-white/80 hover:text-white">✕</button>
          </div>
          <div className="flex items-center gap-2 text-[11px] font-bold text-white/90 flex-shrink-0 mb-2 mt-4">
            <span className="h-2 w-2 rounded-full bg-green-400 shadow-[0_0_8px_rgba(74,222,128,0.5)]" />
            System Ready
          </div>

          <div className="mt-6 flex-grow overflow-y-auto space-y-1 pr-1 custom-scrollbar">
            {displayNavItems.map(([k, label, Icon]) => (
              <button key={k} onClick={() => { setPage(k); localStorage.setItem('admin_active_tab', k); setIsSidebarOpen(false); }} className={`flex w-full items-center gap-2 rounded-md px-3 py-2 text-sm ${page === k ? "bg-white text-[#B71C1C]" : "text-white hover:bg-white/10"}`}>
                <Icon size={16} /> {label}
              </button>
            ))}
          </div>
        </div>

        <div className="p-4 border-t border-white/10 bg-black/5 flex-shrink-0">
          <div className="flex items-center justify-between rounded-lg border border-white/20 p-2">
            <div className="flex items-center gap-2 overflow-hidden">
              <div className="h-7 w-7 rounded-full bg-white/20 flex-shrink-0" />
              <div className="text-[10px] font-bold truncate">{role === 'manager' ? 'Manager User' : 'Admin User'}</div>
            </div>
            <LogOut size={14} className="flex-shrink-0 cursor-pointer hover:text-[#EF9A9A]" onClick={onLogout} />
          </div>
        </div>
      </aside>

      <div className="flex flex-col md:ml-[240px] h-[100dvh] overflow-hidden">
        <header className="sticky top-0 z-20 flex h-16 items-center justify-between border-b border-[#FFCDD2] bg-white px-4 md:px-6 shadow-sm">
            <div className="flex items-center gap-2 md:gap-3 overflow-hidden">
              <button onClick={() => setIsSidebarOpen(true)} className="flex-shrink-0 rounded-md border border-[#FFCDD2] p-2 md:hidden">
                <LayoutDashboard size={18} />
              </button>
              <div className="text-base md:text-xl font-black truncate tracking-tight">{title}</div>
            </div>

            <div className="hidden lg:block text-xs font-medium text-gray-500">
               {new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
            </div>
          <div className="flex items-center gap-3">
            <OutletToggle className="flex" />
            <button className="relative rounded-md border border-[#FFCDD2] p-2">
              <Bell size={16} />
              <span className="absolute -right-1 -top-1 flex h-4 w-4 items-center justify-center rounded-full bg-[#E53935] text-[9px] text-white">3</span>
            </button>
            <div className="h-8 w-8 rounded-full bg-[#FFEBEE]" />
          </div>
        </header>

        <main className="flex-grow overflow-y-auto p-4 md:p-6 bg-[#FFF5F5]">
          {page === "dashboard" && <Dashboard revenue={revenue} ordersCount={ordersCount} activityLog={activityLog} statsLoading={statsLoading} />}
          {page === "tables" && outlet === 'restaurant' && <Tables onOpen={() => {}} />}
          {page === "tables" && outlet === 'bar' && <BarTables />}
          {page === "menu" && outlet === 'restaurant' && <MenuPage onAddDish={() => setDishModalOpen(true)} />}
          {page === "menu" && outlet === 'bar' && <BarMenuPage />}
          {page === "specials" && <TodaySpecials />}
          {page === "orders" && <Orders />}
          {page === "reports" && <Reports />}
          {page === "captains" && (
            <Suspense fallback={<div className="p-4 bg-white border rounded-xl">Loading captain analytics...</div>}>
              <CaptainPerformanceDashboard captains={[]} recentSoldItems={[]} />
            </Suspense>
          )}
          {page === "payroll" && <Payroll onPayslip={() => {}} />}
          {page === "marketing" && <Marketing upload={mUpload} setUpload={setMUpload} uploadRef={mUploadRef} generated={mGenerated} setGenerated={setMGenerated} posted={mPosted} setPosted={setMPosted} />}
          {page === "surveillance" && <SurveillanceDashboard onIncident={() => {}} />}
          {page === "inventory" && <Inventory />}
          {page === "pricing" && <Pricing />}
          {page === "settings" && <SettingsPage />}
        </main>
      </div>

      {role !== 'manager' && (
        <>
          <button onClick={() => setSpireOpen(true)} className="fixed bottom-6 right-6 z-30 flex items-center gap-3 rounded-full bg-[#E53935] px-6 py-4 text-white hover:bg-[#B71C1C] shadow-2xl font-black uppercase tracking-widest text-[11px] transition-all hover:scale-105 active:scale-95 group">
            <Sparkles size={18} className="group-hover:rotate-12 transition-transform" /> Ask Spire ✨
          </button>
          <AIDishCreationModal open={dishModalOpen} onClose={() => setDishModalOpen(false)} onSave={() => setDishModalOpen(false)} />
        </>
      )}

      {/* Spire.ai Assistant Side Drawer */}
      {spireOpen && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-md animate-in fade-in duration-500" onClick={() => setSpireOpen(false)} />
          <div className="relative w-full max-w-[450px] bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-500">
            <div className="bg-[#B71C1C] text-white p-8 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="h-10 w-10 bg-white/20 rounded-xl flex items-center justify-center">
                  <Bot size={24} />
                </div>
                <div>
                   <h3 className="text-xl font-black tracking-tight leading-none">Spire.ai Assistant</h3>
                   <p className="text-[10px] font-bold text-white/60 uppercase tracking-widest mt-1">Operational Intelligence Active</p>
                </div>
              </div>
              <button onClick={() => setSpireOpen(false)} className="h-10 w-10 flex items-center justify-center rounded-full hover:bg-white/10 transition-colors">✕</button>
            </div>
            
            <div className="flex-grow overflow-y-auto p-8 space-y-8 bg-[#FFF9F9]">
               <div className="flex justify-end">
                  <div className="bg-white p-5 rounded-3xl rounded-tr-none border border-red-50 text-sm font-medium shadow-sm max-w-[85%] text-gray-700 leading-relaxed">
                    Where did my 50kg chicken go today?
                  </div>
               </div>
               
               <div className="bg-white p-8 rounded-[40px] border border-red-100 shadow-sm space-y-6 animate-in zoom-in-95 duration-500">
                  <div className="flex items-center gap-2 text-[#B71C1C]">
                     <Sparkles size={18} />
                     <p className="text-[11px] font-black uppercase tracking-[0.2em]">Spire Intelligence</p>
                  </div>
                  <p className="text-base font-bold text-gray-900 leading-tight">
                    Analyzing sales, inventory logs, and camera feeds...
                  </p>
                  <ul className="space-y-3 text-sm font-bold text-gray-700">
                     <li className="flex gap-2"><span>•</span> 12.5kg used in 50 Chicken Dum Biryani plates</li>
                     <li className="flex gap-2"><span>•</span> 35kg remains in cold storage (Fridge 2)</li>
                     <li className="flex gap-2 text-[#E53935] font-black"><span>•</span> 2.5kg discrepancy found.</li>
                  </ul>
                  
                  <div className="relative aspect-[16/10] rounded-[32px] overflow-hidden bg-black group border-[3px] border-[#E53935] shadow-2xl">
                     <div className="absolute top-4 left-4 z-10 bg-[#E53935] text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest animate-pulse">LIVE INCIDENT</div>
                     <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent" />
                     <div className="absolute inset-4 border-2 border-[#E53935]/30 rounded-2xl animate-pulse" />
                     
                     <div className="absolute bottom-4 left-6 right-6 flex items-end justify-between">
                        <div>
                           <p className="text-xs font-black text-white">Unauthorized Access</p>
                           <p className="text-[9px] font-bold text-white/50">Zone: Cold Storage #2</p>
                        </div>
                        <p className="text-[10px] font-black text-white/70 tabular-nums">14:32:07</p>
                     </div>
                  </div>
               </div>
            </div>
            
            <div className="p-8 bg-white border-t border-gray-100">
               <div className="flex gap-3">
                  <div className="flex-grow relative">
                    <input className="w-full p-4 bg-gray-50 border-none rounded-2xl text-sm font-medium focus:ring-2 focus:ring-red-100" placeholder="Ask Spire anything..." />
                  </div>
                  <button className="h-14 w-14 bg-[#B71C1C] text-white rounded-2xl flex items-center justify-center shadow-lg shadow-red-100 hover:scale-105 active:scale-95 transition-all"><Send size={24} /></button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

