      particles: styleId === 'explosion' ? 'spices' : styleId === 'festival' ? 'gold-dust' : 'none',
      blur: styleId === 'dark' || styleId === 'luxury' ? 5 : 0
    }
  };
};

export const renderToCanvas = (canvas, config, foodImage, bgImage) => {
  const ctx = canvas.getContext('2d');
  const w = canvas.width;
  const h = canvas.height;

  // 1. Draw Background
  if (bgImage) {
    const bgScale = Math.max(w / bgImage.width, h / bgImage.height);
    const bgW = bgImage.width * bgScale;
    const bgH = bgImage.height * bgScale;
    ctx.drawImage(bgImage, (w - bgW) / 2, (h - bgH) / 2, bgW, bgH);
  } else {
    ctx.fillStyle = '#111';
    ctx.fillRect(0, 0, w, h);
  }

  // 2. Apply Atmospheric Lighting & Vignette
  const vignette = ctx.createRadialGradient(w / 2, h / 2, w / 4, w / 2, h / 2, w);
  vignette.addColorStop(0, 'rgba(0,0,0,0)');
  vignette.addColorStop(1, `rgba(0,0,0,${config.effects.vignette})`);
  ctx.fillStyle = vignette;
  ctx.fillRect(0, 0, w, h);

  // 3. Draw Particles (Spices/Gold Dust)
  if (config.effects.particles !== 'none') {
    ctx.save();
    for (let i = 0; i < 40; i++) {
      const px = Math.random() * w;
      const py = Math.random() * h;
      const size = Math.random() * 3;
      ctx.fillStyle = config.effects.particles === 'spices' ? '#8B0000' : '#FFD700';
      ctx.globalAlpha = 0.4 + Math.random() * 0.4;
      ctx.beginPath();
      ctx.arc(px, py, size, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();
  }

  // 4. Draw Food Image
  if (foodImage) {
    ctx.save();
    const foodW = w * config.food.scale;
    const foodH = (foodImage.height / foodImage.width) * foodW;
    const foodX = w * config.food.x;
    const foodY = h * config.food.y;

    ctx.translate(foodX, foodY);
    ctx.rotate(config.food.rotate * Math.PI / 180);

    // Dynamic Shadow based on lighting
    ctx.shadowBlur = config.food.shadowBlur;
    ctx.shadowColor = config.food.shadowColor;
    ctx.shadowOffsetX = 10;
    ctx.shadowOffsetY = 15;

    if (config.food.glow > 0) {
      ctx.shadowBlur = config.food.glow;
      ctx.shadowColor = STYLES.find(s => s.id === config.style).primary;
    }

    ctx.drawImage(foodImage, -foodW / 2, -foodH / 2, foodW, foodH);

    // Food Shine / Highlights
    if (config.food.shine) {
      ctx.globalCompositeOperation = 'screen';
      const shine = ctx.createLinearGradient(-foodW / 2, -foodH / 2, foodW / 2, foodH / 2);
      shine.addColorStop(0, 'rgba(255,255,255,0)');
      shine.addColorStop(0.5, 'rgba(255,255,255,0.2)');
      shine.addColorStop(1, 'rgba(255,255,255,0)');
      ctx.fillStyle = shine;
      ctx.fillRect(-foodW / 2, -foodH / 2, foodW, foodH);
    }

    ctx.restore();
  }

  // 5. Draw Typography
  ctx.save();
  const style = STYLES.find(s => s.id === config.style);
  ctx.font = `black ${config.text.main.fontSize}px ${style.font === 'serif' ? 'Playfair Display, serif' : 'Montserrat, sans-serif'}`;
  ctx.fillStyle = '#fff'; // Usually white for premium cinematic look
  ctx.textAlign = config.text.main.align;
  ctx.textBaseline = 'middle';

  const textX = w * config.text.main.x;
  const textY = h * config.text.main.y;

  // Text Shadow/Glow
  ctx.shadowBlur = 10;
  ctx.shadowColor = 'rgba(0,0,0,0.5)';

  if (config.style === 'neon') {
    ctx.shadowBlur = 20;
    ctx.shadowColor = style.primary;
    ctx.strokeStyle = style.secondary;
    ctx.lineWidth = 1;
    ctx.strokeText(config.text.main.content, textX, textY);
  }

  ctx.fillText(config.text.main.content, textX, textY);

  // Secondary Text
  ctx.font = `bold 10px Montserrat, sans-serif`;
  ctx.globalAlpha = 0.7;
  ctx.letterSpacing = '2px';
  ctx.fillText(config.text.secondary.content, textX, textY + (config.text.main.y > 0.5 ? -30 : 35));

  ctx.restore();

  // 6. Final Polish Color Overlay
  ctx.globalCompositeOperation = 'overlay';
  ctx.fillStyle = style.primary;
  ctx.globalAlpha = 0.05;
  ctx.fillRect(0, 0, w, h);
};

import { useState, useEffect, useCallback } from "react";
import { fetchMenuFromBackend } from "./menuService";

const STORAGE_KEY = "softshape_unified_menu";

let globalMenu = null;
let _isLoading = true;
let _loadError = null;
const subscribers = new Set();
let loadPromise = null;

function dispatchMenuEvent(menu) {
  try {
    window.dispatchEvent(
      new CustomEvent("softshape_menu_updated", { detail: menu })
    );
  } catch (_) {}
}

function notifySubscribers() {
  subscribers.forEach((callback) =>
    callback({
      menu: globalMenu ?? [],
      loading: _isLoading,
      error: _loadError,
    })
  );
}

async function loadInitialMenu() {
  if (loadPromise) return loadPromise;

  loadPromise = (async () => {
    _isLoading = true;
    _loadError = null;
    notifySubscribers();

    try {
      const apiItems = await fetchMenuFromBackend();
      const saved = localStorage.getItem(STORAGE_KEY);
      const localItems = saved ? JSON.parse(saved) : [];

      const localSpecials = localItems.filter((i) => i.isSpecial);
      const specialNames = new Set(localSpecials.map((s) => s.n.toLowerCase()));
      const filteredBase = apiItems.filter(
        (m) => !specialNames.has(m.n.toLowerCase())
      );

      globalMenu = [...localSpecials, ...filteredBase];
      console.log(`[MenuSync] Loaded ${globalMenu.length} items from backend`);
    } catch (err) {
      console.error("[MenuSync] Failed to load initial menu", err);
      _loadError =
        err?.message ||
        "Could not reach backend. Check VITE_API_URL and backend deployment.";
      const saved = localStorage.getItem(STORAGE_KEY);
      globalMenu = saved ? JSON.parse(saved) : [];
    }

    _isLoading = false;
    if (globalMenu?.length) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(globalMenu));
    }
    notifySubscribers();
    dispatchMenuEvent(globalMenu ?? []);
  })();

  try {
    await loadPromise;
  } finally {
    loadPromise = null;
  }
}

export function useGlobalMenuSync() {
  const [menu, setMenu] = useState(() => {
    if (globalMenu) return globalMenu;
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [loading, setLoading] = useState(_isLoading);
  const [error, setError] = useState(_loadError);

  useEffect(() => {
    const handleUpdate = ({ menu: newMenu, loading: isLoading, error: err }) => {
      setMenu(newMenu ?? []);
      setLoading(isLoading);
      setError(err);
    };

    subscribers.add(handleUpdate);
    handleUpdate({
      menu: globalMenu,
      loading: _isLoading,
      error: _loadError,
    });

    loadInitialMenu();

    return () => {
      subscribers.delete(handleUpdate);
    };
  }, []);

  const setGlobalMenu = useCallback((updater) => {
    const nextMenu =
      typeof updater === "function"
        ? updater(globalMenu || menu || [])
        : updater;

    globalMenu = nextMenu;
    _isLoading = false;
    _loadError = null;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(nextMenu));

    setMenu(nextMenu);
    notifySubscribers();
    dispatchMenuEvent(nextMenu);
  }, [menu]);

  const refreshMenu = useCallback(async () => {
    _isLoading = true;
    _loadError = null;
    notifySubscribers();

    try {
      const apiItems = await fetchMenuFromBackend();

      const activeSpecials = (globalMenu || menu || []).filter(
        (i) =>
          i.isSpecial &&
          i.active &&
          (!i.expiresAt || Date.now() < i.expiresAt)
      );
      const specialNames = new Set(
        activeSpecials.map((s) => s.n.toLowerCase())
      );
      const filteredBase = apiItems.filter(
        (m) => !specialNames.has(m.n.toLowerCase())
      );
      globalMenu = [...activeSpecials, ...filteredBase];
      _loadError = null;

      localStorage.setItem(STORAGE_KEY, JSON.stringify(globalMenu));
      setMenu(globalMenu);
      notifySubscribers();
      dispatchMenuEvent(globalMenu);

      return apiItems;
    } catch (err) {
      _loadError = err?.message || "Menu refresh failed";
      notifySubscribers();
      throw err;
    } finally {
      _isLoading = false;
      notifySubscribers();
    }
  }, [menu]);

  // Sync menu changes across different browser tabs
  useEffect(() => {
    const handleStorageChange = (e) => {
      if (e.key === STORAGE_KEY && e.newValue) {
        try {
          const newMenu = JSON.parse(e.newValue);
          globalMenu = newMenu;
          setMenu(newMenu);
          notifySubscribers();
        } catch (err) {
          console.error("Failed to parse menu from storage", err);
        }
      }
    };
    window.addEventListener("storage", handleStorageChange);
    return () => window.removeEventListener("storage", handleStorageChange);
  }, []);

  return {
    globalMenu: menu || [],
    isLoadingMenu: loading,
    loadError: error,
    setGlobalMenu,
    refreshMenu,
  };
}

