source:
import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, ArrowRight } from 'lucide-react';

const FOOD_ITEMS = ['🍔', '🍕', '🥟', '🍣', '🍟'];

export default function SliceChallenge({ onComplete, onSkip }) {
  const [round, setRound] = useState(0); // 0, 1, 2
  const [isSliced, setIsSliced] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const [totalDiscount, setTotalDiscount] = useState(0);
  
  // Game state
  const [currentItem, setCurrentItem] = useState(FOOD_ITEMS[0]);
  const [slashPos, setSlashPos] = useState(null);

  const rewards = [
    { text: '5% OFF!', value: 5 },
    { text: 'Better Luck Next Time', value: 0 },
    { text: '1% OFF!', value: 1 }
  ];

  // Spawn new item for each round
  useEffect(() => {
    if (round < 3 && !showResult) {
      setCurrentItem(FOOD_ITEMS[Math.floor(Math.random() * FOOD_ITEMS.length)]);
      setIsSliced(false);
      setSlashPos(null);
    }
  }, [round, showResult]);

  const handleSlice = (e) => {
    if (isSliced || round >= 3) return;

    // Vibrate feedback if supported
    if (navigator.vibrate) navigator.vibrate(50);

    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX || (e.touches && e.touches[0].clientX) || rect.left + rect.width / 2;
    const y = e.clientY || (e.touches && e.touches[0].clientY) || rect.top + rect.height / 2;

    setSlashPos({ x, y });
    setIsSliced(true);

    const reward = rewards[round];
    setTotalDiscount(prev => prev + reward.value);

    // After brief slice animation, proceed to next round
    setTimeout(() => {
      if (round === 2) {
        setShowResult(true);
      } else {
        setRound(prev => prev + 1);
      }
    }, 1500);
  };

  if (showResult) {
    return (
      <div className="fixed inset-0 bg-gray-900 flex flex-col items-center justify-center p-6 z-[100] font-['Inter',sans-serif]">
        
        {/* Confetti Particles */}
        {Array.from({ length: 20 }).map((_, i) => (
          <motion.div
            key={i}
            className="absolute w-2 h-2 rounded-full"
            style={{ backgroundColor: ['#FF4D4F', '#FFD700', '#4CAF50', '#2196F3'][i % 4] }}
            initial={{ x: 0, y: 0, opacity: 1 }}
            animate={{ 
              x: (Math.random() - 0.5) * window.innerWidth, 
              y: -window.innerHeight + Math.random() * 500,
              opacity: 0,
              rotate: Math.random() * 360
            }}
            transition={{ duration: 2, ease: "easeOut" }}
          />
        ))}

        <motion.div 
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          transition={{ type: "spring", bounce: 0.5 }}
          className="bg-white/10 backdrop-blur-xl border border-white/20 rounded-[40px] p-8 max-w-sm w-full text-center shadow-[0_0_50px_rgba(255,77,79,0.3)] relative overflow-hidden"
        >
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-[#FF4D4F]/20 to-transparent pointer-events-none" />
          
          <div className="w-20 h-20 mx-auto bg-gradient-to-r from-[#FF4D4F] to-[#FF6B6B] rounded-full flex items-center justify-center mb-6 shadow-[0_10px_20px_rgba(255,77,79,0.4)]">
            <Sparkles className="text-white w-10 h-10 animate-pulse" />
          </div>
          
          <h2 className="text-3xl font-black text-white mb-2 tracking-tighter">Awesome!</h2>
          <p className="text-xl font-bold text-gray-300 mb-8">
            🎉 Total <span className="text-[#FF4D4F]">{totalDiscount}% Reward</span> Unlocked
          </p>
          
          <button 
            onClick={() => onComplete(totalDiscount)}
            className="w-full py-4 rounded-full bg-gradient-to-r from-[#FF4D4F] to-[#FF6B6B] text-white font-black uppercase tracking-widest hover:scale-105 active:scale-95 transition-all shadow-[0_15px_30px_rgba(255,77,79,0.3)] flex items-center justify-center gap-2"
          >
            View Menu <ArrowRight size={18} />
          </button>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-gray-900 overflow-hidden z-[100] font-['Inter',sans-serif]">
      {/* Neon Glows */}
      <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-[#FF4D4F]/20 rounded-full blur-[100px] pointer-events-none animate-[pulse_4s_ease-in-out_infinite]" />
      <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-pink-500/20 rounded-full blur-[100px] pointer-events-none animate-[pulse_6s_ease-in-out_infinite]" />
      
      {/* Header */}
      <div className="absolute top-10 left-0 w-full px-6 flex justify-between items-start z-10">
        <div>
          <h1 className="text-2xl font-black text-white uppercase tracking-tighter">
            Slice & Unlock
          </h1>
          <p className="text-[10px] font-black text-[#FF4D4F] uppercase tracking-[0.2em] mt-1">
            {3 - round} chances left
          </p>
        </div>
        <button onClick={onSkip} className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-white transition-colors">
          Skip
        </button>
      </div>

      {/* Dynamic Unlocked Tracker */}
      <div className="absolute top-10 right-6 text-right z-10">
        <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Unlocked</p>
        <p className="text-2xl font-black text-[#FF4D4F]">{totalDiscount}%</p>
      </div>

      {/* Play Area */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <AnimatePresence mode="wait">
          {!isSliced ? (
            <motion.div
              key={`item-${round}`}
              initial={{ y: window.innerHeight, x: (Math.random() - 0.5) * 100, rotate: 0 }}
              animate={{ 
                y: -100, 
                x: (Math.random() - 0.5) * 200, 
                rotate: 360 
              }}
              transition={{ 
                y: { duration: 2.5, ease: "easeOut", repeat: Infinity, repeatType: "mirror" },
                x: { duration: 3, ease: "easeInOut", repeat: Infinity, repeatType: "mirror" },
                rotate: { duration: 4, ease: "linear", repeat: Infinity }
              }}
              className="text-8xl pointer-events-auto cursor-crosshair select-none relative"
              onPointerDown={handleSlice}
              style={{ touchAction: 'none' }} // prevent scrolling
            >
              {/* Floating Trail */}
              <motion.div 
                className="absolute inset-0 bg-[#FF4D4F] rounded-full blur-xl opacity-30"
                animate={{ scale: [1, 1.2, 1] }}
                transition={{ duration: 1, repeat: Infinity }}
              />
              {currentItem}
            </motion.div>
          ) : (
            <motion.div
              key={`sliced-${round}`}
              initial={{ scale: 1 }}
              animate={{ scale: 1.2, opacity: 0 }}
              transition={{ duration: 0.5 }}
              className="absolute pointer-events-none"
              style={{ left: slashPos?.x - 50, top: slashPos?.y - 50 }}
            >
              <div className="text-8xl filter blur-[2px] opacity-50 relative">
                {currentItem}
                
                {/* Slash Effect */}
                <motion.div 
                  initial={{ scaleX: 0, opacity: 1 }}
                  animate={{ scaleX: 2, opacity: 0 }}
                  transition={{ duration: 0.3 }}
                  className="absolute top-1/2 left-1/2 w-48 h-2 bg-white -translate-x-1/2 -translate-y-1/2 shadow-[0_0_20px_#FF4D4F] origin-left rotate-45"
                />

                {/* Splash Particles */}
                {Array.from({ length: 8 }).map((_, i) => (
                  <motion.div
                    key={i}
                    className="absolute top-1/2 left-1/2 w-4 h-4 bg-[#FF4D4F] rounded-full blur-[1px]"
                    initial={{ x: 0, y: 0, scale: 1 }}
                    animate={{ 
                      x: (Math.random() - 0.5) * 200, 
                      y: (Math.random() - 0.5) * 200,
                      scale: 0,
                      opacity: 0
                    }}
                    transition={{ duration: 0.6, ease: "easeOut" }}
                  />
                ))}
              </div>

              {/* Score Popup */}
              <motion.div
                initial={{ y: 50, opacity: 0, scale: 0.5 }}
                animate={{ y: -50, opacity: 1, scale: 1 }}
                transition={{ type: "spring", bounce: 0.6 }}
                className={`absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 whitespace-nowrap text-2xl font-black ${rewards[round].value > 0 ? 'text-[#FF4D4F]' : 'text-gray-400'} drop-shadow-[0_5px_10px_rgba(0,0,0,0.5)]`}
              >
                {rewards[round].text}
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Floating Embers Background */}
      <div className="absolute inset-0 pointer-events-none opacity-40">
        {Array.from({ length: 15 }).map((_, i) => (
          <motion.div
            key={`ember-${i}`}
            className="absolute w-1 h-1 bg-[#FF4D4F] rounded-full blur-[1px]"
            initial={{ 
              x: Math.random() * window.innerWidth, 
              y: window.innerHeight + Math.random() * 200 
            }}
            animate={{ 
              y: -100,
              x: `calc(${Math.random() * 100}vw)`,
              opacity: [0, 1, 0]
            }}
            transition={{ 
              duration: 3 + Math.random() * 4, 
              repeat: Infinity, 
              ease: "linear" 
            }}
          />
        ))}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import CustomerMenu from './CustomerMenu';
import SliceChallenge from './SliceChallenge';
import BarMenu from './BarMenu';
import { motion } from 'framer-motion';
import { UtensilsCrossed, GlassWater, Sparkles, ArrowRight } from 'lucide-react';

export default function UserMenuApp() {
  const { tableId } = useParams();
  const navigate = useNavigate();
  
  // 'selection', 'engagement', 'menu', 'bar-menu'
  const [view, setView] = useState('selection');
  const [discountAmount, setDiscountAmount] = useState(0);

  useEffect(() => {
    if (!tableId) {
      navigate('/user-menu/table-1', { replace: true });
    }
  }, [tableId, navigate]);

  if (!tableId) return null;

  if (view === 'selection') {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center bg-[#FFF5F5] p-6 relative overflow-hidden font-['Inter',sans-serif]">
        {/* Abstract Background Blurs */}
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-[#FF4D4F]/5 rounded-full blur-[120px] pointer-events-none" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-[#B71C1C]/5 rounded-full blur-[120px] pointer-events-none" />
        
        {/* Top Header/Logo */}
        <motion.div 
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="mb-8 text-center z-10"
        >
          <img 
            src="/logo softshape.ai.png" 
            alt="softshape.ai" 
            className="h-44 md:h-52 w-auto object-contain mx-auto" 
          />
          <h1 className="text-xl font-black text-gray-500 uppercase tracking-[0.2em] mt-2">
            Welcome to Table {tableId.replace('table-', '')}
          </h1>
        </motion.div>

        {/* Experience Cards */}
        <div className="grid w-full max-w-3xl grid-cols-1 gap-6 sm:grid-cols-2 z-10 px-4">
          
          {/* Restaurant Experience */}
          <motion.button 
            initial={{ opacity: 0, x: -50 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.1 }}
            onClick={() => setView('engagement')}
            className="group relative flex flex-col items-start rounded-[32px] border-2 border-white bg-white/80 backdrop-blur-xl p-8 shadow-[0_20px_40px_rgba(255,77,79,0.04)] transition-all duration-500 hover:border-[#FF4D4F] hover:bg-white hover:translate-y-[-8px] text-left cursor-pointer"
          >
            <div className="absolute top-6 right-6 bg-red-50 text-[#FF4D4F] px-3.5 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider flex items-center gap-1 shadow-sm">
              <Sparkles size={10} className="animate-pulse" /> Play & Win
            </div>
            
            <div className="mb-6 rounded-2xl bg-red-50 p-4 text-[#FF4D4F] transition-all duration-500 group-hover:scale-110 group-hover:bg-[#FF4D4F] group-hover:text-white shadow-inner">
              <UtensilsCrossed size={32} strokeWidth={2.5} />
            </div>
            
            <h2 className="text-2xl font-black text-gray-900 tracking-tighter uppercase">Dining Room</h2>
            <p className="mt-3 text-[13px] font-semibold leading-relaxed text-gray-500">
              Play our quick table game to win exclusive food discounts, then browse our full range of starters, mains, and desserts.
            </p>
            
            <div className="mt-6 flex items-center gap-2 text-[#FF4D4F] text-[11px] font-black uppercase tracking-widest group-hover:translate-x-1 transition-transform">
              Proceed <ArrowRight size={14} />
            </div>
          </motion.button>

          {/* Bar Experience */}
          <motion.button 
            initial={{ opacity: 0, x: 50 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
            onClick={() => setView('bar-menu')}
            className="group relative flex flex-col items-start rounded-[32px] border-2 border-white bg-white/80 backdrop-blur-xl p-8 shadow-[0_20px_40px_rgba(183,28,28,0.04)] transition-all duration-500 hover:border-[#B71C1C] hover:bg-white hover:translate-y-[-8px] text-left cursor-pointer"
          >
            <div className="absolute top-6 right-6 bg-red-50/50 text-[#B71C1C] px-3.5 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider shadow-sm">
              ⚡ Direct Entry
            </div>

            <div className="mb-6 rounded-2xl bg-[#FFF5F5] p-4 text-[#B71C1C] transition-all duration-500 group-hover:scale-110 group-hover:bg-[#B71C1C] group-hover:text-white shadow-inner">
              <GlassWater size={32} strokeWidth={2.5} />
            </div>
            
            <h2 className="text-2xl font-black text-gray-900 tracking-tighter uppercase">Bar & Lounge</h2>
            <p className="mt-3 text-[13px] font-semibold leading-relaxed text-gray-500">
              Skip the game. Browse our premium craft beers, imported liquor, signature cocktails, and gourmet lounge pairings immediately.
            </p>
            
            <div className="mt-6 flex items-center gap-2 text-[#B71C1C] text-[11px] font-black uppercase tracking-widest group-hover:translate-x-1 transition-transform">
              Proceed <ArrowRight size={14} />
            </div>
          </motion.button>

        </div>

        <footer className="mt-16 flex flex-col items-center gap-4 z-10">
          <p className="text-[11px] font-black uppercase tracking-[0.5em] text-[#B71C1C]/40 drop-shadow-sm">
            Powered by softshape.ai
          </p>
        </footer>
      </div>
    );
  }

  if (view === 'engagement') {
    return (
      <SliceChallenge 
        onComplete={(totalDiscount) => {
          setDiscountAmount(totalDiscount);
          setView('menu');
        }}
        onSkip={() => setView('menu')}
      />
    );
  }

  if (view === 'bar-menu') {
    return <BarMenu tableId={tableId} />;
  }

  return <CustomerMenu tableId={tableId} discountPercentage={discountAmount} />;
}

/**
 * QZ Tray printer utility
 *
 * Handles:
 *   - Setting up QZ Tray security (certificate + SHA512 signing via backend)
 *   - Connecting to QZ Tray WebSocket (wss://localhost:8181)
 *   - Sending print jobs to the three printers
 *
 * Environment variables (Vite — must be prefixed with VITE_):
 *   VITE_BACKEND_URL             – Backend base URL (e.g. https://softshape-backend.onrender.com)
 *   VITE_KOT_FOOD_PRINTER_NAME  – Exact Windows printer name for food KOT
 *   VITE_KOT_LIQUOR_PRINTER_NAME – Exact Windows printer name for liquor/bar KOT
 *   VITE_RECEIPT_PRINTER_NAME   – Exact Windows printer name for cashier receipt
 *
 * QZ Tray must be running on the bar PC and listening on wss://localhost:8181.
 * If QZ Tray is not running, all print functions throw a clear error message.
 */

import qz from "qz-tray";
import { QZ_CERT } from "../services/certificate.js";

const BACKEND_URL = import.meta.env.VITE_BACKEND_URL ?? "";

// ─── Security Setup ───────────────────────────────────────────────────────────

let _setupDone = false;

/**
 * Configure QZ Tray security once.
 * - Certificate: loaded from constants/certificate.js (public, safe to commit)
 * - Signing: done server-side via POST /api/print/qz-sign (private key never leaves Render)
 */
function setupQZ() {
  if (_setupDone) return;
  _setupDone = true;

  qz.security.setCertificatePromise((_resolve, _reject) => {
    _resolve(QZ_CERT);
  });

  qz.security.setSignatureAlgorithm("SHA512");

  qz.security.setSignaturePromise((toSign) => {
    return (resolve, reject) => {
      fetch(`${BACKEND_URL}/api/print/qz-sign`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ toSign }),
      })
        .then((r) => {
          if (!r.ok) throw new Error(`QZ sign request failed: ${r.status}`);
          return r.json();
        })
        .then((data) => resolve(data.signature))
        .catch((err) => {
          console.error("[qzPrinter] Signing error:", err);
          reject(err);
        });
    };
  });
}

// ─── Connection ───────────────────────────────────────────────────────────────

/**
 * Connect to QZ Tray if not already connected.
 * Throws a clear message if QZ Tray is not running on the PC.
 */
export async function connectQZ() {
  setupQZ();

  if (qz.websocket.isActive()) return;

  try {
    await qz.websocket.connect();
  } catch (err) {
    const msg =
      "QZ Tray is not running. Please start QZ Tray on the printer PC and try again.";
    console.error("[qzPrinter]", msg, err);
    throw new Error(msg);
  }
}

// ─── Print Helpers ────────────────────────────────────────────────────────────

/**
 * Send ESC/POS data to a named printer via QZ Tray.
 * @param printerName - Exact Windows printer name
 * @param data - Array returned by the backend build* functions
 */
async function sendToPrinter(printerName, data) {
  await connectQZ();

  const config = qz.configs.create(printerName);
  await qz.print(config, data);
}

// ─── Public API ───────────────────────────────────────────────────────────────

/** Send data to the Food KOT printer (kitchen) */
export async function printToFoodKOT(data) {
  const printerName = import.meta.env.VITE_KOT_FOOD_PRINTER_NAME;
  if (!printerName) throw new Error("VITE_KOT_FOOD_PRINTER_NAME is not configured");
  await sendToPrinter(printerName, data);
}

/** Send data to the Liquor KOT printer (bar) */
export async function printToLiquorKOT(data) {
  const printerName = import.meta.env.VITE_KOT_LIQUOR_PRINTER_NAME;
  if (!printerName) throw new Error("VITE_KOT_LIQUOR_PRINTER_NAME is not configured");
  await sendToPrinter(printerName, data);
}

/** Send data to the Receipt printer (cashier) */
export async function printToReceipt(data) {
  const printerName = import.meta.env.VITE_RECEIPT_PRINTER_NAME;
  if (!printerName) throw new Error("VITE_RECEIPT_PRINTER_NAME is not configured");
  await sendToPrinter(printerName, data);
}
